#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

int a[1005][1005], sa[1005][1005];

int main(){
	int n, m, c;
	cin >> n >> m >> c;
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= m; j++)
			cin >> a[i][j];
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= m; j++)
			sa[i][j] = sa[i - 1][j] + sa[i][j - 1] - sa[i - 1][j - 1] + a[i][j];
	int mn = -2e9, mx, my;
	for(int i = 1; i <= n - c + 1; i++)
		for(int j = 1; j <= m - c + 1; j++)
		{
			int v = sa[i + c - 1][j + c - 1] - sa[i + c - 1][j - 1] - sa[i - 1][j + c - 1] + sa[i - 1][j - 1];
			if(v > mn)
			{
				mn = v;
				mx = i;
				my = j;
			}
		}
	cout << mx << ' ' << my;
	return 0;
}
